mapper.select:
SELECT id, parent_id, reply_to_comment_id, reply_to_nickname, author_nickname, author_site, content_html, created_at FROM t_comment WHERE parent_id IN
#{parentId}
AND audit_status = 1 AND deleted = 0 ORDER BY created_at ASC, id ASC

where.if:
AND (
    author_nickname LIKE #{keyword}
    OR content_md LIKE #{keyword}
)

mapper.update:
UPDATE t_comment
SET audit_status = #{status.databaseValue},
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
WHERE id = #{id}
  AND deleted = 0
